(108, 121, 'Standard Queen Room', 'A comfortable room perfect for solo travelers or couples, conveniently located near the airport.', 3000.00, 2, '1 Queen Bed', 'images/rooms/air_inn_standard_queen.jpeg', 'AC,Wi-Fi,TV,Airport Shuttle,Attached Bath', '2025-06-06 07:45:24'),
(109, 121, 'Executive Twin Room', 'A spacious room with two single beds, ideal for business travelers or friends.', 4000.00, 2, '2 Single Beds', 'images/rooms/air_inn_executive_twin.jpeg', 'AC,Wi-Fi,TV,Work Desk,Mini Fridge,Attached Bath', '2025-06-06 07:45:24'),
(110, 90, 'Basic Fan Room', 'A simple and clean room with a fan, suitable for budget travelers.', 1200.00, 2, '1 Double Bed', 'images/rooms/anwara_guesthouse_basic_fan.jpeg', 'Fan,Attached Bath,Basic amenities', '2025-06-06 07:45:24'),
(111, 90, 'Standard Double Room', 'A basic room with essential furnishings for a comfortable short stay.', 1500.00, 2, '1 Double Bed', 'images/rooms/anwara_guesthouse_standard_double.jpeg', 'Fan,Attached Bath,Clean Linen,Chair', '2025-06-06 07:45:24'),
